#!/usr/bin/env bash
# Generated by OrchestKit Claude Plugin
# Created: 2026-05-12

# ============================================================================
# Hook exec-form lint gate
# ============================================================================
# Asserts every entry in src/hooks/hooks.json uses the args: string[] (exec)
# form introduced in CC 2.1.139, not the legacy string-with-spaces form.
#
# Why: the string form is shell-parsed by CC, which means ${VAR} placeholders
# need defensive quoting and any path with spaces silently fails on some
# platforms. The args[] form spawns directly via execve, eliminating that
# whole class of bugs.
#
# To convert any new entries: node scripts/codemod/hooks-to-args-form.mjs
#
# Issue: #1774 (M138)
# ============================================================================
set -euo pipefail

SCRIPT_DIR="$(cd "$(dirname "${BASH_SOURCE[0]}")" && pwd)"
PROJECT_ROOT="${CLAUDE_PROJECT_DIR:-$(cd "$SCRIPT_DIR/../.." && pwd)}"

if [[ -t 1 ]]; then
    RED='\033[0;31m'; GREEN='\033[0;32m'; NC='\033[0m'
else
    RED=''; GREEN=''; NC=''
fi

HOOKS_JSON="$PROJECT_ROOT/src/hooks/hooks.json"
if [[ ! -f "$HOOKS_JSON" ]]; then
    echo -e "${RED}FAIL${NC}: $HOOKS_JSON not found"
    exit 1
fi

echo "Hook exec-form lint (M138 #1774)"
echo "================================"

# Use node so we walk the JSON structure properly (avoids regex false-positives
# on string values that happen to contain a space).
NODE_OUT=$(node -e '
  const fs = require("fs");
  const root = JSON.parse(fs.readFileSync(process.argv[1], "utf8"));
  const offenders = [];

  function visit(node, path) {
    if (Array.isArray(node)) {
      node.forEach((n, i) => visit(n, path + "[" + i + "]"));
      return;
    }
    if (node && typeof node === "object") {
      if (Array.isArray(node.hooks)) {
        node.hooks.forEach((entry, i) => {
          if (!entry || typeof entry !== "object") return;
          if ("args" in entry) return; // OK: args[] form
          if (typeof entry.command !== "string") return;
          // String form: only acceptable if it has no whitespace (single binary).
          if (/\s/.test(entry.command)) {
            offenders.push(path + ".hooks[" + i + "]: " + entry.command);
          }
        });
      }
      Object.keys(node).forEach(k => visit(node[k], path + "." + k));
    }
  }
  visit(root, "$");
  if (offenders.length === 0) {
    console.log("OK: " + countArgsEntries(root) + " entries in args[] form, 0 in legacy string form");
    process.exit(0);
  }
  console.error("FAIL: " + offenders.length + " entr" + (offenders.length === 1 ? "y" : "ies") + " still in legacy string form:");
  offenders.slice(0, 20).forEach(o => console.error("  - " + o));
  if (offenders.length > 20) console.error("  ... +" + (offenders.length - 20) + " more");
  console.error("");
  console.error("Fix: node scripts/codemod/hooks-to-args-form.mjs");
  process.exit(1);

  function countArgsEntries(node) {
    let n = 0;
    function walk(x) {
      if (Array.isArray(x)) { x.forEach(walk); return; }
      if (x && typeof x === "object") {
        if (Array.isArray(x.hooks)) x.hooks.forEach(e => { if (e && "args" in e) n++; });
        Object.values(x).forEach(walk);
      }
    }
    walk(node);
    return n;
  }
' "$HOOKS_JSON")
RC=$?

if [[ $RC -eq 0 ]]; then
    echo -e "  ${GREEN}✓${NC} $NODE_OUT"
else
    echo "$NODE_OUT"
    exit 1
fi

echo ""
echo "Results: PASS"
